<?/* * ajouter un cadeau */$id=filter_input(1,'id',FILTER_VALIDATE_INT);$referrer=filter_input(INPUT_POST,'referrer',FILTER_DEFAULT);//echo $referrer;die;if(!$id){    $_SESSION['msg'] = "Une Erreur c'est produite";    $_SESSION['type'] = "alert-danger";    redirect('ListeCadeaux');}if(filter_input(INPUT_POST,'addGift',FILTER_VALIDATE_INT)):$data=array(  'titre'=>filter_input(0,'titre',FILTER_SANITIZE_STRING),  'bare_code'=>str_replace(' ','',filter_input(0,'bare_code',FILTER_SANITIZE_STRING)),  'code_article'=>str_replace(' ','',filter_input(0,'code_article',FILTER_SANITIZE_STRING)),  'point_bonus'=>filter_input(0,'point_bonus',257),  'qte'=>filter_input(0,'qte',257),  'dispo'=>filter_input(0,'dispo') ? 1 : 0,  'description'=>filter_input(0,'description',FILTER_SANITIZE_STRING),    'paht'=>filter_input(0,'paht',516),    'pvht'=>filter_input(0,'pvht',516),    'famille'=>filter_input(0,'famille',257),    'pvttc'=>filter_input(0,'pvttc',516),    'stoc_alert'=>filter_input(0,'stoc_alert',516),    'cree_par'=>$_SESSION['user']['id']);    if (update($id,$data, 'grm_gift')) {        $_SESSION['msg'] = "Cadeaux modifier";        $_SESSION['type'] = "alert-success";        redirect('ListeCadeaux');    } else {        $_SESSION['msg'] = "Une Erreur c'est produite";        $_SESSION['type'] = "alert-danger";        redirect('ListeCadeaux');    }endif;    if(is_int($id)){        $Cadeaux=get("*",'grm_gift',array('id='=>$id));        $CadeauxDetails=$Cadeaux['reponse'][0];    }else{        $Cadeaux=get("*",'grm_gift',array('code_article LIKE '=>$id.'%','bare_code='=>$id),'OR');        $CadeauxDetails=$Cadeaux['reponse'][0];        if(count($CadeauxDetails)<=0){            $_SESSION['msg'] = "Article non Trouver !!";            $_SESSION['type'] = "alert-danger";             redirect('ListeCadeaux');        }    }?><section class="content-header">    <h1> Editer un article</h1></section><!-- Main content --><section class="content">    <div class="row">    <form method="post" class="returPage">        <div class="col-md-4 ">            <div class="box box-primary box-body">                <div class="form-group">                    <label>Titre/Nom du cadeaux</label>                    <input type="text" value="<?=$CadeauxDetails['titre']?>" name="titre" class="form-control" required>                </div>                <div class="form-group ">                    <label>Code à bare </label>                    <input type="text" value="<?=$CadeauxDetails['bare_code']?>" name="bare_code" class="form-control" required>                </div>                <div class="form-group ">                    <label>Code article </label>                    <input type="text" value="<?=$CadeauxDetails['code_article']?>" name="code_article" class="form-control" required>                </div>                <div class="form-group">                    <label>Nombre de point bonus</label>                    <input type="number" value="<?=$CadeauxDetails['point_bonus']?>" min="0" step="1" name="point_bonus" class="form-control" required>                </div>                <div class="form-group">                    <label>Quantité initital : </label>                    <input type="number"   step="1" value="<?=$CadeauxDetails['qte']?>" name="qte" class="form-control"  readonly>                </div>								                    </div>        </div>        <div class="col-md-4">            <div class="box box-success box-body">                <div class="form-group">                    <label>PAHT</label>                    <input type="text" name="paht" value="<?=$CadeauxDetails['paht']?>" class="form-control">                    </div>            <div class="form-group">                <label>PVHT</label>                <input type="text" name="pvht" value="<?=$CadeauxDetails['pvht']?>" class="form-control">            </div>        <div class="form-group">            <label>PVTTC</label>            <input type="text" name="pvttc" value="<?=$CadeauxDetails['pvttc']?>" class="form-control">        </div>                <div class="form-group">                    <label>Stock Alert</label>                    <input type="number" step="1" min="0" name="stoc_alert" value="<?=$CadeauxDetails['stoc_alert']?>" class="form-control">                </div>            </div>        </div>        <div class="col-md-4">            <div class="box box-primary box-body">                <div class="form-group">                    <label class="hidden">                        <input type="checkbox" name="serialisable"  class="switcher" > Cadeaux avec numéro de serie                    </label>                </div>                <div class="form-group">                    <label>                        <input type="checkbox" name="dispo" class="switcher" <?=$CadeauxDetails['dispo']==0 ? "checked" : ""?> > Disponible                    </label>                </div>                <div class="form-group">                    <label>Famille</label>                    <select name="famille" class="form-control" required>                        <option value=""></option>                        <? $Familes=get("*",'grm_gift_family');                        foreach ($Familes['reponse'] as $fami):                            ?>                            <option value="<?=$fami['id']?>"  <? if($CadeauxDetails['famille']==$fami['id']) echo 'selected="selected"'?> > <?=$fami['nom']?></option>                        <?endforeach;?>                    </select>                </div>                <div class="form-group">                    <label>Description : </label>                    <textarea name="description" cols="8" rows="3" class="form-control"><?=$CadeauxDetails['description']?></textarea>                </div>            </div>        </div><div class="col-md-12">    <div class="box box-danger">        <br/>    <button type="submit" value="1" name="addGift" class="btn btn-github pull-right pad">Modifier le cadeaux</button>        <a href="#" class="btn btn-danger pull-left pad" onclick="history.go(-1);"> Annuler </a>        <br/><div class="clearfix"></div><br/></div></div>    </form>    </div>    </section>